-- تصحيح مؤشرات "قيادة العملية التعليمية" (6 مؤشرات صحيحة)
UPDATE indicators SET text = 'تعزِّز المدرسة القيم الإسلامية والهوية الوطنية.' WHERE code = '1-2-1-1';
UPDATE indicators SET text = 'تلتزم المدرسة بقيم مهنة التعليم وأخلاقياتها.' WHERE code = '1-2-1-2';
UPDATE indicators SET text = 'توفِّر المدرسة مناخاً آمناً للتعلم والنمو نفسياً واجتماعياً.' WHERE code = '1-2-1-3';
UPDATE indicators SET text = 'تنشر المدرسة قواعد السلوك والمواطنة، وتتابع تطبيقها.' WHERE code = '1-2-1-4';
UPDATE indicators SET text = 'توفِّر المدرسة برامج وأنشطة تربوية داعمة للسلوك الإيجابي.' WHERE code = '1-2-1-5';
INSERT INTO indicators (code, text, criteriaId) 
SELECT '1-2-1-6', 'توفِّر المدرسة برامج وأنشطة إثرائية غير صفية؛ لتطوير مواهب الأطفال، وتهيئتهم للمستقبل.', id 
FROM criteria WHERE name = 'قيادة العملية التعليمية'
ON DUPLICATE KEY UPDATE text = 'توفِّر المدرسة برامج وأنشطة إثرائية غير صفية؛ لتطوير مواهب الأطفال، وتهيئتهم للمستقبل.';

-- تصحيح مؤشرات "التطوير المؤسسي" (7 مؤشرات)
UPDATE indicators SET text = '(*)توفِّر المدرسة كادراً تعليمياً مكتملاً ومؤهلاً.' WHERE code = '1-4-1-1';
UPDATE indicators SET text = '(*)توفِّر المدرسة كادراً إدارياً مكتملاً ومؤهلاً.' WHERE code = '1-4-1-2';
UPDATE indicators SET text = '(*)تُظهر المدرسة ثباتاً واستدامة مالية.' WHERE code = '1-4-1-3';
UPDATE indicators SET text = 'تشجِّع المدرسة منسوبيها للحصول على الرخصة المهنية.' WHERE code = '1-4-1-4';
UPDATE indicators SET text = 'تدعم المدرسة التطوير المهني لمنسوبيها وفقاً لنتائج تقويم الأداء الوظيفي واحتياجاتهم.' WHERE code = '1-4-1-5';
UPDATE indicators SET text = 'تطبِّق المدرسة التقويم الذاتي المبنيَّ على المعايير المعتمدة من الهيئة.' WHERE code = '1-4-1-6';
UPDATE indicators SET text = 'تنفِّذ المدرسة خطة للتحسين بناءً على نتائج التقويم المدرسي، وتتابعها.' WHERE code = '1-4-1-7';

-- تصحيح مؤشرات "حقوق الطفل وحمايته" (3 مؤشرات صحيحة)
UPDATE indicators SET text = 'تلتزم المدرسة بحماية الأطفال من الأذى بكل أنواعه.' WHERE code = '1-5-1-1';
UPDATE indicators SET text = 'تعزِّز المدرسة وعي الأطفال بخدمات حماية الطفل وكيفية الوصول إليها.' WHERE code = '1-5-1-2';
UPDATE indicators SET text = 'تلتزم المدرسة بالمحافظة على صحة الأطفال ومتابعة تغذيتهم.' WHERE code = '1-5-1-3';

